    35→
    36→@freezed
    37→abstract class Team with _$Team {
    38→  const Team._();
    39→
    40→  @JsonSerializable(
    41→    explicitToJson: true,
    42→    fieldRename: Constants.modelFieldRename,
    43→  )
    44→  const factory Team({
    45→    @Default(null) String? id,
    46→    @Default(null) String? name,
    47→    @Default(null) String? ownerUserId,
    48→    @Default(TeamType.multiple) TeamType teamType,
    49→    @Default(null) DateTime? createdAt, // assumes UTC
    50→    @Default(null) DateTime? updatedAt, // assumes UTC
    51→    @Default(null) DateTime? teamPlanCancelAt,
    52→    @Default(null) DateTime? teamPlanDowngradeAt,
    53→    @Default(null) String? imageUrl,
    54→    @Default(null) TeamPlan? teamPlan,
    55→    @Default(null) TeamPlan? nextTeamPlan,
    56→    @Default(null) String? presignedImageUrl,
    57→    @Default(null) String? billingFailureReason,
