    60→  }) = _Team;
    61→
    62→  factory Team.fromJson(Map<String, dynamic> json) => _$TeamFromJson(json);
    63→
    64→  bool get isSingleUserTeam => teamType == TeamType.single;
    65→
    66→  /// ボール解析の使用量（TeamPlan + Item の合算）
    67→  int get ballUsage {
    68→    final planUsage =
    69→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.currentUsage ?? 0 : 0;
    70→    final itemUsage = item?.ballUsage ?? 0;
    71→    return planUsage + itemUsage;
    72→  }
    73→
    74→  /// AI コーチの使用量（TeamPlan + Item の合算）
    75→  int get aiCoachUsage {
    76→    final planUsage = (teamPlan?.withinPeriod ?? false)
    77→        ? teamPlan?.currentAiCoachUsage ?? 0
    78→        : 0;
    79→    final itemUsage = item?.aiCoachUsage ?? 0;
    80→    return planUsage + itemUsage;
    81→  }
    82→
    83→  /// ボール解析の上限数（Plan + Item の合算）
    84→  int get maxBalls {
    85→    final planMax =
    86→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    87→    final itemMax = item?.ballAvailableCount ?? 0;
    88→    return planMax + itemMax;
    89→  }
    90→
    91→  /// AI コーチの上限数（Plan + Item の合算）
    92→  int get maxAICoachCount {
