    99→
   100→  /// プランの契約・有効期限状態
   101→  TeamPlanStatus get teamPlanStatus {
   102→    // 1. teamPlanがnullまたはisActive!=trueの場合
   103→    if (teamPlan == null || teamPlan!.isActive != true) {
   104→      return TeamPlanStatus.noContract;
   105→    }
   106→
   107→    // 2. 期限切れか
   108→    final now = _resolveTeamPlanNow();
   109→    final endDate = teamPlan!.endDate;
   110→    // 以下の場合は nextTeamPlan の endDate を使用する
   111→    // 1. nextTeamPlan が存在
   112→    // 2. nextTeamPlan の isPendingActivation が true
   113→    // 3. teamPlan の endDate が nextTeamPlan の startDate と同じ (連続してプランを継続している)
   114→    final effectiveEndDate = (nextTeamPlan != null &&
   115→            nextTeamPlan!.isPendingActivation == true &&
   116→            endDate == nextTeamPlan!.startDate)
   117→        ? nextTeamPlan!.endDate
   118→        : endDate;
   119→    final isExpired =
   120→        effectiveEndDate != null && effectiveEndDate.isBefore(now);
   121→    if (isExpired) {
   122→      if (nextTeamPlan != null && nextTeamPlan!.isPendingActivation == true) {
   123→        return TeamPlanStatus.nextPlanPending;
   124→      }
   125→      return TeamPlanStatus.expired;
   126→    }
   127→
   128→    // 3. 期限警告（30日以内）
   129→    if (effectiveEndDate != null) {
   130→      final oneMonthLater = now.add(const Duration(days: 30));
   131→      if (effectiveEndDate.isAfter(now) &&
   132→          effectiveEndDate.isBefore(oneMonthLater)) {
   133→        return TeamPlanStatus.expiringSoon;
   134→      }
   135→    }
   136→
   137→    // 4. 問題なし
   138→    return TeamPlanStatus.ok;
   139→  }
   140→
   141→  /// ボール解析の使用量状態
   142→  BallAnalysisUsageStatus get ballAnalysisUsageStatus {
   143→    // プランが無効な場合は上限到達扱い
   144→    if (teamPlan == null || teamPlan!.isActive != true) {
   145→      return BallAnalysisUsageStatus.limitReached;
   146→    }
   147→
   148→    final usage = ballUsage;
   149→    final maxUsage = maxBalls;
   150→
   151→    // 上限到達
   152→    if (usage >= maxUsage) {
   153→      return BallAnalysisUsageStatus.limitReached;
   154→    }
   155→
   156→    // 上限接近（90%以上）
   157→    if (usage >= (maxUsage * 0.9).floor()) {
   158→      return BallAnalysisUsageStatus.limitApproaching;
   159→    }
   160→
   161→    // 正常
   162→    return BallAnalysisUsageStatus.ok;
   163→  }
   164→
   165→  /// AI コーチの使用量状態
   166→  AICoachUsageStatus get aiCoachUsageStatus {
   167→    // プランが無効な場合は上限到達扱い
   168→    if (teamPlan == null || teamPlan!.isActive != true) {
   169→      return AICoachUsageStatus.limitReached;
   170→    }
   171→
   172→    final usage = aiCoachUsage;
   173→    final maxUsage = maxAICoachCount;
   174→
   175→    // 上限到達
   176→    if (usage >= maxUsage) {
   177→      return AICoachUsageStatus.limitReached;
   178→    }
   179→
   180→    // 上限接近（90%以上）
   181→    if (usage >= (maxUsage * 0.9).floor()) {
   182→      return AICoachUsageStatus.limitApproaching;
   183→    }
   184→
   185→    // 正常
   186→    return AICoachUsageStatus.ok;
   187→  }
   188→
   189→  /// ボール解析が実行可能かどうか（プラン状態と使用量の両方をチェック）
   190→  bool get canAnalyzeBall {
   191→    return teamPlanStatus.isValid && ballAnalysisUsageStatus.canAnalyze;
   192→  }
   193→
   194→  /// AI コーチが利用可能かどうか（プラン状態と使用量の両方をチェック）
   195→  bool get canUseAiCoach {
   196→    return teamPlanStatus.isValid && aiCoachUsageStatus.canUseAiCoach;
   197→  }
   198→}
   199→
   200→/// チームプランの契約・有効期限に関する状態
   201→enum TeamPlanStatus {
   202→  // アプリ利用不可
   203→  noContract, // 有料プラン契約なし
   204→  nextPlanPending, // 次回プランが保留中
   205→  expired, // 期限切れ
